  colorButtonSecondary: "#ECECEC",
  colorButtonSecondaryHover: "#DBDBDB",
  colorButtonDisabled: "#F5F5F5",

  // Border
  colorBorderLight: "#F5F5F5",
  colorBorderDark: "#E9E9EB",
  colorBorderHover: "#CFCFD1",
  colorBorderSubtle: "#EFF1F4",
