  const _drFmtRecognition = (v) => { if (v == null || v === 0) return null; const abs = Math.abs(v); return "(£" + abs.toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ")"; };
