  const _aiStickyCol1 = { position: "sticky", left: _aiStickyCol1Left, zIndex: 3, background: T.colorSurfacePrimary, borderRight: "1px solid " + _aiBorderClr, boxShadow: "4px 0 8px -2px rgba(0,0,0,0.1)" };
