                  onMouseLeave={function(e) { if (!checked) { e.currentTarget.style.boxShadow = "inset 0 0 0 1px #E9E9EB"; var cb = e.currentTarget.querySelector(".file-checkbox"); if (cb) cb.style.border = "1px solid #DBDBDB"; } }}
